  ('heelevel3-7ec62a85-moex-00246', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '依司法院釋字第469號解釋，有關國家賠償之成立，下列敘述何者錯誤？', '["公務員依法對特定人民負有作為義務而已無不作為之裁量餘地，倘故意過失怠於執行職務時， 有國家賠償之適用", "公務員在裁量收縮至零之情況下違反法律規定，此違法不僅是客觀法秩序違反，容有公權利侵 害之可能", "透過新保護規範理論，得探究系爭規定是否於立法目的上有保護特定之當事人，以為其主張救 濟之依據", "國家賠償之請求權限於法律明確規定特定人享有向行政機關為一定作為之請求權者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00247', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '下列何者非屬損失補償之適用範圍？', '["主管機關勘查測量風景區範圍，進入私人土地造成農作物或地上物毀損", "私有古蹟或歷史建築坐落於第三人土地上，限制土地所有權使用收益", "學童依法律接種疫苗後發生嚴重疾病或身心障礙", "農民依主管機關行政指導休耕某作物後，因該作物價格暴漲，造成農民損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
